// ============ Google OAuth 登录 ============
const GOOGLE_OAUTH_CONFIG = {
  client_id: process.env.GOOGLE_CLIENT_ID,
  client_secret: process.env.GOOGLE_CLIENT_SECRET,
  auth_url: 'https://accounts.google.com/o/oauth2/v2/auth',
  token_url: 'https://oauth2.googleapis.com/token',
  userinfo_url: 'https://www.googleapis.com/oauth2/v2/userinfo',
  scopes: 'email profile',
};

// 获取正确的回调基础URL（用于OAuth重定向URI）
function getCallbackBaseUrl(req) {
  const host = req.get('host') || '';
  // Render/生产环境使用 HTTPS，即使内部转发是 HTTP
  const isSecure = req.secure || req.get('x-forwarded-proto') === 'https'
    || host.includes('.onrender.com') || host.includes('chenjuntrading.cn');
  const protocol = isSecure ? 'https' : 'http';
  
  // 生产环境
  if (host.includes('chenjuntrading.cn')) {
    return 'https://api.chenjuntrading.cn';
  }
  
  // Render环境 - 强制 HTTPS
  if (host.includes('.onrender.com')) {
    return `https://${host}`;
  }
  
  // 开发环境
  if (host.includes('localhost') || host.includes('127.0.0.1')) {
    return 'http://localhost:8089';
  }
  
  // 默认使用环境变量
  if (process.env.API_BASE_URL) {
    return process.env.API_BASE_URL;
  }
  
  // 兜底
  return 'https://claw-backend-2026.onrender.com';
}

// 获取前端URL（用于授权成功后重定向回前端）
function getFrontendUrl(req) {
  // 优先级1：环境变量
  if (process.env.FRONTEND_URL) {
    return process.env.FRONTEND_URL;
  }
  
  // 优先级2：Referer
  const referer = req.headers.referer;
  if (referer) {
    try {
      const refUrl = new URL(referer);
      return `${refUrl.protocol}//${refUrl.host}`;
    } catch {}
  }
  
  // 优先级3：已知前端域名
  const knownFrontends = [
    'https://chenjuntrading.cn',
    'https://claw-app-2026.pages.dev',
    'https://claw.pages.dev',
  ];
  
  const origin = req.headers.origin;
  if (origin && knownFrontends.includes(origin)) {
    return origin;
  }
  
  // 兜底
  return 'https://chenjuntrading.cn';
}

// GET /api/auth/google - 发起 Google 授权
router.get('/google', (req, res) => {
  const clientId = GOOGLE_OAUTH_CONFIG.client_id;
  if (!clientId) {
    return res.status(503).json({
      success: false,
      error: 'Google 登录未配置（GOOGLE_CLIENT_ID 未设置）',
      hint: '请在环境变量中配置 GOOGLE_CLIENT_ID 和 GOOGLE_CLIENT_SECRET'
    });
  }

  const callbackBase = getCallbackBaseUrl(req);
  const redirectUri = `${callbackBase}/api/auth/google/callback`;
  
  console.log('[认证] Google OAuth 回调URL:', redirectUri);

  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: 'code',
    scope: GOOGLE_OAUTH_CONFIG.scopes,
    access_type: 'online',
    prompt: 'select_account',
  });

  const authUrl = `${GOOGLE_OAUTH_CONFIG.auth_url}?${params.toString()}`;
  console.log('[认证] 发起 Google OAuth 登录');
  res.redirect(authUrl);
});

// GET /api/auth/google/callback - Google OAuth 回调
router.get('/google/callback', async (req, res) => {
  const { code, error } = req.query;
  const frontendUrl = getFrontendUrl(req);

  if (error) {
    console.error('[认证] Google OAuth 错误:', error);
    return res.redirect(`${frontendUrl}?auth_error=google_denied`);
  }

  if (!code) {
    return res.redirect(`${frontendUrl}?auth_error=no_code`);
  }

  try {
    const clientId = GOOGLE_OAUTH_CONFIG.client_id;
    const clientSecret = GOOGLE_OAUTH_CONFIG.client_secret;
    const callbackBase = getCallbackBaseUrl(req);
    const redirectUri = `${callbackBase}/api/auth/google/callback`;
    
    console.log('[认证] Google OAuth 回调处理，使用重定向URI:', redirectUri);

    // 用 code 换取 access_token
    const tokenRes = await axios.post(GOOGLE_OAUTH_CONFIG.token_url, new URLSearchParams({
      code,
      client_id: clientId,
      client_secret: clientSecret,
      redirect_uri: redirectUri,
      grant_type: 'authorization_code',
    }).toString(), {
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });

    const { access_token } = tokenRes.data;

    // 获取 Google 用户信息
    const userInfoRes = await axios.get(GOOGLE_OAUTH_CONFIG.userinfo_url, {
      headers: { Authorization: `Bearer ${access_token}` },
    });

    const googleUser = {
      email: userInfoRes.data.email,
      name: userInfoRes.data.name || userInfoRes.data.email.split('@')[0],
      picture: userInfoRes.data.picture,
    };

    console.log('[认证] Google OAuth 登录成功:', googleUser.email);

    // 查找或创建用户
    let user = await findUserByEmailPG(googleUser.email);
    if (!user) {
      user = findUserByEmailJSON(googleUser.email);
    }

    let userId;
    if (!user) {
      // 创建新用户（Google 用户无需密码）
      userId = generateUserId();
      const newUser = {
        id: userId,
        email: googleUser.email,
        name: googleUser.name,
        role: 'user',
        plan: 'free',
        loginType: 'google',
        picture: googleUser.picture,
        createdAt: new Date().toISOString(),
      };
      createUser(newUser);
      syncUserToPostgres({ ...newUser, password: null }).catch(() => {});
      user = { ...newUser };
    } else {
      userId = user.id;
    }

    // 生成 JWT
    const token = jwt.sign(
      makeJwtPayload(userId, googleUser.email, user.role),
      JWT_SECRET
    );

    // 重定向回前端，携带 token
    res.redirect(`${frontendUrl}?google_token=${token}&google_user=${encodeURIComponent(JSON.stringify({
      id: userId, email: googleUser.email, name: googleUser.name, role: user.role || 'user', plan: user.plan || 'free'
    }))}`);

  } catch (err) {
    console.error('[认证] Google OAuth 回调处理失败:', err.response?.data || err.message);
    res.redirect(`${frontendUrl}?auth_error=google_callback_failed`);
  }
});

export default router;
